+import type { AnyColumn } from '~/column.ts';
+import { SQL, sql, type SQLChunk, type SQLWrapper } from '../sql.ts';
+
+type ExpressionValue<T extends SQLWrapper> = T extends SQL<infer TValue> ? TValue
+	: T extends AnyColumn ? T['_']['data']
+	: unknown;
+
+export type WindowOrderBy = SQLWrapper;
+export type WindowBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| { readonly type: 'preceding' | 'following'; readonly value: number };
+
+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly from: WindowBoundary;
+	readonly to: WindowBoundary;
+}
+
+export interface WindowSpec {
+	partitionBy?: WindowOrderBy | WindowOrderBy[];
+	orderBy?: WindowOrderBy | WindowOrderBy[];
+	frame?: WindowFrame;
+}
+
+export const unboundedPreceding = { type: 'unboundedPreceding' } as const;
+export const currentRow = { type: 'currentRow' } as const;
+export const unboundedFollowing = { type: 'unboundedFollowing' } as const;
+
+function positionalArgument(value: number): SQL {
+	return sql.raw(String(value));
+}
+
+function validateBoundaryValue(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	}
+}
+
+export function preceding(value: number): WindowBoundary {
+	validateBoundaryValue('preceding', value);
+	return { type: 'preceding', value };
+}
+
+export function following(value: number): WindowBoundary {
+	validateBoundaryValue('following', value);
+	return { type: 'following', value };
+}
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	switch (boundary.type) {
+		case 'unboundedPreceding': return -Infinity;
+		case 'preceding': return -boundary.value;
+		case 'currentRow': return 0;
+		case 'following': return boundary.value;
+		case 'unboundedFollowing': return Infinity;
+	}
+}
+
+function frame(type: WindowFrame['type'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+function buildBoundary(boundary: WindowBoundary): SQL {
+	switch (boundary.type) {
+		case 'unboundedPreceding': return sql.raw('unbounded preceding');
+		case 'currentRow': return sql.raw('current row');
+		case 'unboundedFollowing': return sql.raw('unbounded following');
+		case 'preceding': return sql`${positionalArgument(boundary.value)} preceding`;
+		case 'following': return sql`${positionalArgument(boundary.value)} following`;
+	}
+}
+
+/** @internal */
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const chunks: SQLChunk[] = [];
+	const partitionBy = spec.partitionBy === undefined ? [] : Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
+	const orderBy = spec.orderBy === undefined ? [] : Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
+	if (partitionBy.length) chunks.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	if (orderBy.length) chunks.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	if (spec.frame) chunks.push(sql`${sql.raw(spec.frame.type)} between ${buildBoundary(spec.frame.from)} and ${buildBoundary(spec.frame.to)}`);
+	return sql.join(chunks, sql` `);
+}
+
+export class WindowFunction<T> extends SQL<T> {
+	constructor(private readonly expression: SQL<T>) {
+		super(expression.queryChunks);
+	}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLChunk[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function validatePositiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer; received ${value}`);
+	}
+}
+
+export const rowNumber = (): WindowFunction<number> => windowFunction('row_number');
+export const rank = (): WindowFunction<number> => windowFunction('rank');
+export const denseRank = (): WindowFunction<number> => windowFunction('dense_rank');
+export function ntile(buckets: number): WindowFunction<number> {
+	validatePositiveInteger('ntile', buckets);
+	return windowFunction('ntile', [positionalArgument(buckets)]);
+}
+export const percentRank = (): WindowFunction<number> => windowFunction('percent_rank');
+export const cumeDist = (): WindowFunction<number> => windowFunction('cume_dist');
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<ExpressionValue<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: ExpressionValue<T> | SQLWrapper): WindowFunction<Exclude<ExpressionValue<T>, null>>;
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: ExpressionValue<T> | SQLWrapper): WindowFunction<unknown> {
+	const args: SQLChunk[] = [expression];
+	if (offset !== undefined) args.push(positionalArgument(offset));
+	if (defaultValue !== undefined) args.push(defaultValue as SQLChunk);
+	return windowFunction('lag', args);
+}
+
+export function lead<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<ExpressionValue<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: ExpressionValue<T> | SQLWrapper): WindowFunction<Exclude<ExpressionValue<T>, null>>;
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: ExpressionValue<T> | SQLWrapper): WindowFunction<unknown> {
+	const args: SQLChunk[] = [expression];
+	if (offset !== undefined) args.push(positionalArgument(offset));
+	if (defaultValue !== undefined) args.push(defaultValue as SQLChunk);
+	return windowFunction('lead', args);
+}
+
+export const firstValue = <T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null> => windowFunction('first_value', [expression]);
+export const lastValue = <T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null> => windowFunction('last_value', [expression]);
+export function nthValue<T extends SQLWrapper>(expression: T, nth: number): WindowFunction<ExpressionValue<T> | null> {
+	validatePositiveInteger('nthValue', nth);
+	return windowFunction('nth_value', [expression, positionalArgument(nth)]);
+}
+
+export const windowSum = (expression: SQLWrapper): WindowFunction<string | null> => windowFunction('sum', [expression]);
+export const windowAvg = (expression: SQLWrapper): WindowFunction<string | null> => windowFunction('avg', [expression]);
+export const windowMin = <T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null> => windowFunction('min', [expression]);
+export const windowMax = <T extends SQLWrapper>(expression: T): WindowFunction<ExpressionValue<T> | null> => windowFunction('max', [expression]);
+export const windowCount = (expression?: SQLWrapper): WindowFunction<number> => windowFunction('count', [expression ?? sql.raw('*')]);
